#include<bits/stdc++.h>
using namespace std;
vector<int> mp[500010];
map<int,int> mp1[500010];
int n,m,t,h[500010];
int deg[500010],to[500010];
int del[500010],vis[500010],ne[500010];
vector<int> ans;
void dfs(int x,int from=0)
{
    if(from)
    {
        if(vis[from])
        {
            printf("NIE\n");
            exit(0);
        }
        vis[from]=true;
    }
    if(from)
    {
        dfs(to[from],ne[from]);
    }
    else
    {
        while(!mp[x].empty())
        {
            int id=mp[x].back();
            mp[x].pop_back();
            if(del[id])
            {
                continue;
            }
            del[id]=true;
            dfs(to[id],ne[id]);
        }
    }
    ans.push_back(x);
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        mp[x].push_back(i);
        to[i]=y;
        mp1[x][y]=i;
        deg[x]++;
        deg[y]--;
    }
    for(int i=1;i<=n;i++)
    {
        if(deg[i]!=0)
        {
            printf("NIE");
            return 0;
        }
    }
    scanf("%d",&t);
    while(t--)
    {
        int k,now,nxt;
        scanf("%d%d%d",&k,&now,&nxt);
        k-=2;
        int lst=mp1[now][nxt];
        if(lst==0)
        {
            printf("NIE");
            return 0;
        }
        while(k--)
        {
            int x;
            scanf("%d",&x);
            int id=mp1[nxt][x];
            if(id==0||(ne[lst]&&ne[lst]!=id))
            {
                printf("NIE");
                return 0;
            }
            ne[lst]=id;
            del[id]=true;
            now=nxt;
            nxt=x;
            lst=id;
        }
    }
    dfs(1);
    if(ans.size()!=m+1)
    {
        printf("NIE");
        return 0;
    }
    printf("TAK\n");
    reverse(ans.begin(),ans.end());
    for(int i:ans)
    {
        printf("%d\n",i);
    }
    return 0;
}
